ruleSearch.coverUrl:
//a[last()-2]/@href
@js:
var href = result;
var bookId1 = href.match(/(\d+)\/(\d+)/);
var bookId = (bookId1 && bookId1[2])?bookId1[2]:'0';
var prefix;
if (bookId.length <= 3) {
	prefix = '0';
} else {
	prefix = bookId.slice(0, bookId.length - 3);
}
'https://image.biqige.info/' + prefix + '/' + bookId + '/' + bookId + 's.jpg';

ruleContent.content:
@js:
function d(a, b) {
    b = java.md5Encode(b);
    var d = b.substring(0, 16);
    var e = b.substring(16);
    return java.aesBase64DecodeToString(
        a, 
        e, 
        "AES/CBC/PKCS5Padding", 
        d
    );
}

eval(result.match(/(d\("[\s\S]+?"\))\)/)[1]);

