ruleToc.nextTocUrl:
@js:{
    var nextUrl = '';
    try {
        var doc = org.jsoup.Jsoup.parse(result);
        var count = doc.select('.book_list2 > ul > li').size();
        if (count >= 100) {
            var url = baseUrl;
            if (url.indexOf('index_') > 0) {
                var numMatch = /index_(\d+)\.html/.exec(url);
                if (numMatch) {
                    var num = parseInt(numMatch[1]) + 1;
                    nextUrl = url.replace(/index_(\d+)\.html/, 'index_' + num + '.html');
                }
            } else if (url.endsWith('.html')) {
                nextUrl = url.replace(/\.html$/, '/index_2.html');
            }
        }
    } catch (e) {}
    nextUrl;
}

